package CineTime.aula_spring.controller;

import java.util.ArrayList;
import java.util.List;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import CineTime.aula_spring.model.Filme;

@RestController
@RequestMapping("/filmes")
@CrossOrigin("*")
public class FilmeController {
    @GetMapping
    public ResponseEntity<List<Filme>>listAll(){
        List<Filme> filmes = List.of();
        new Filme(
            "Gato de Botas2",
            "animação",
            "https://www.bing.com/ck/a?!&&p=9cc7beb46f93a0ed52ff0bc6bd37a26e319bd35147e58461501879cebbbef2f1JmltdHM9MTc3NDY1NjAwMA&ptn=3&ver=2&hsh=4&fclid=0a5545a0-3af3-612c-3d21-50353b42602a&u=a1L2ltYWdlcy9zZWFyY2g_cT1mb3RvK2dhdG8rZGUrYm90YXMrMiZpZD0wMTYzQTg2RTRGNjRENzIyMjMzN0Q4ODE1NEFCRTZBMzZDOEMyREIyJkZPUk09SUFDRklS&ntb=1"
        );
        new Filme(
            "as viagens de chihiro",
            "animação",
            "data:image/webp;base64,"
        );
        return ResponseEntity.ok(filmes);
    }

    private List<Filme> listaFilmes = new ArrayList<>();

    @GetMapping
    public List<Filme> listarTodos() {
        return listaFilmes;
    }

    @PostMapping
    public ResponseEntity<Filme> adicionarFilme(
            @RequestBody Filme novoFilme) {

        if (novoFilme.getTitulo() == null
                || novoFilme.getTitulo().isBlank()) {
            return ResponseEntity.badRequest().build();
        }

        listaFilmes.add(novoFilme);

        return ResponseEntity.status(201).body(novoFilme);
    }
}


